package com.careeros.watchlist.domain;
import com.careeros.company.domain.Company; import jakarta.persistence.*; import java.util.UUID; import org.hibernate.annotations.UuidGenerator;
@Entity @Table(name="watchlist_companies") public class WatchlistCompany { @Id @UuidGenerator private UUID id; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="watchlist_id") private Watchlist watchlist; @ManyToOne(fetch=FetchType.EAGER) @JoinColumn(name="company_id") private Company company; private int priority; private boolean enabled; protected WatchlistCompany(){} WatchlistCompany(Watchlist w,Company c,int p,boolean e){if(p<0||p>100)throw new IllegalArgumentException("priority must be 0..100");watchlist=w;company=c;priority=p;enabled=e;} public Company getCompany(){return company;} public int getPriority(){return priority;} public boolean isEnabled(){return enabled;} }
